solution_code:
#include <iostream>
#include <string>

class Registry {
    static inline int s_count{ 0 };
public:
    static void add() {
        ++s_count;
    }

    static void printCount() {
        std::cout << "Registered: " << s_count << "\n";
    }
};

int main() {
    int n;
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i) {
        std::string name;
        std::cin >> name;
        Registry::add();
    }
    Registry::printCount();
    return 0;
}

