solution_code:
#include <iostream>

class ScoreCard {
    static inline int s_best{ 0 };
public:
    static void submit(int score) {
        if (score > s_best)
            s_best = score;
    }

    static void printBest() {
        std::cout << "Best: " << s_best << "\n";
    }
};

int main() {
    int n;
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i) {
        int score;
        std::cin >> score;
        ScoreCard::submit(score);
    }
    ScoreCard::printBest();
    return 0;
}
